const raw = $json.stdout || $json.data || $json.response || '';
const now = new Date().toISOString();
const dirty = /^(?: M|A |D |R |C |U|\?\?)/m.test(raw);
const blocks = [ { type: 'header', text: { type: 'plain_text', text: '💾 Automated Backup' } }, { type: 'context', elements: [ { type: 'mrkdwn', text: `*Checked:* ${now}` }, { type: 'mrkdwn', text: `*Repo:* ${dirty ? 'Changed' : 'Clean'}` } ] }, { type: 'divider' }, { type: 'section', text: { type: 'mrkdwn', text: dirty ? 'Working tree has changes to capture.' : 'Nothing new to back up right now.' } } ];
return [{ json: { checkedAt: now, slackText: `💾 Automated backup: ${dirty ? 'changes present' : 'clean'}`, slackBlocks: blocks } }];
